# 1. Exact-match evaluator — fully deterministic
def exact_match(run, example):
    predicted = (run.outputs or {}).get("answer", "").strip().lower()
    reference = (example.outputs or {}).get("answer", "").strip().lower()
    return {"key": "exact_match", "score": int(predicted == reference)}

# 2. Contains-answer evaluator — partial credit
def contains_answer(run, example):
    predicted = (run.outputs or {}).get("answer", "").lower()
    reference = (example.outputs or {}).get("answer", "").lower()
    score = 1 if reference in predicted else 0
    return {"key": "contains_answer", "score": score}

# 3. Length-penalty evaluator — penalise verbose answers
def brevity(run, example):
    answer = (run.outputs or {}).get("answer", "")
    score = 1.0 if len(answer) < 200 else max(0.0, 1.0 - (len(answer) - 200) / 800)
    return {"key": "brevity", "score": round(score, 3)}

