# Custom LLM-as-judge with explicit prompt
from langchain_openai import ChatOpenAI
from langsmith.evaluation import run_evaluator

@run_evaluator
def llm_judge(run, example):
    question = (example.inputs or {}).get("question", "")
    answer = (run.outputs or {}).get("answer", "")
    reference = (example.outputs or {}).get("answer", "")

    judge_llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)
    verdict = judge_llm.invoke(
        f"Question: {question}\n"
        f"Reference answer: {reference}\n"
        f"Model answer: {answer}\n"
        "Is the model answer correct? Reply with just 1 (yes) or 0 (no)."
    ).content.strip()

    try:
        score = int(verdict)
    except ValueError:
        score = 0
    return {"key": "llm_judge", "score": score}

