from langsmith.evaluation import evaluate_comparative

def pairwise_judge(runs, example):
    """Returns 0 if runs[0] is better, 1 if runs[1] is better, 0.5 if tie."""
    a = (runs[0].outputs or {}).get("answer", "")
    b = (runs[1].outputs or {}).get("answer", "")
    question = (example.inputs or {}).get("question", "")

    judge = ChatOpenAI(model="gpt-4o", temperature=0)
    verdict = judge.invoke(
        f"Question: {question}\n"
        f"Answer A: {a}\n"
        f"Answer B: {b}\n"
        "Which answer is more accurate and concise? Reply with 'A', 'B', or 'tie'."
    ).content.strip().upper()

    if verdict == "A":
        return {"key": "pairwise_winner", "scores": {runs[0].id: 1, runs[1].id: 0}}
    elif verdict == "B":
        return {"key": "pairwise_winner", "scores": {runs[0].id: 0, runs[1].id: 1}}
    else:
        return {"key": "pairwise_winner", "scores": {runs[0].id: 0.5, runs[1].id: 0.5}}

# Compare two previously-run experiments
evaluate_comparative(
    [
        "gpt-4o-mini-v1-<timestamp>",   # experiment A name from LangSmith
        "gpt-4o-v1-<timestamp>",         # experiment B name from LangSmith
    ],
    evaluators=[pairwise_judge],
)

import pytest
from types import SimpleNamespace

def make_run(answer: str):
    return SimpleNamespace(outputs={"answer": answer}, inputs={})

def make_example(reference: str, question: str = ""):
    return SimpleNamespace(
        outputs={"answer": reference},
        inputs={"question": question},
    )

def test_exact_match_correct():
    result = exact_match(make_run("Paris"), make_example("Paris"))
    assert result["score"] == 1

def test_exact_match_wrong():
    result = exact_match(make_run("London"), make_example("Paris"))
    assert result["score"] == 0

def test_exact_match_case_insensitive():
    result = exact_match(make_run("PARIS"), make_example("paris"))
    assert result["score"] == 1

def test_brevity_short_answer():
    result = brevity(make_run("42"), make_example("42"))
    assert result["score"] == 1.0

def test_brevity_long_answer():
    result = brevity(make_run("x" * 1000), make_example("anything"))
    assert result["score"] < 0.3
